  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/tracked_areas',
  headers,
  qs: {
    select: 'council_slug'
  }
});

// 2. Deduplicate council slugs
const seen = new Set();
const slugs = [];
for (const area of areas) {
  if (area.council_slug && !seen.has(area.council_slug)) {
    seen.add(area.council_slug);
    slugs.push(area.council_slug);
  }
